export default function hideModals() {
  const popupTable = document.querySelector(".unavailable-popup-table");
  const productTable = document.querySelector(
    ".unavailable__table-wrapper--products"
  );
  const categoriesTable = document.querySelector(
    ".unavailable__table-wrapper--categories"
  );
  const overlay = document.querySelector(".overlay");

  const noResultsMessage = categoriesTable?.querySelector(
    ".unavailable__no-results"
  );

  popupTable.classList.remove("unavailable-popup-table--active");
  productTable.classList.add("unavailable__table-wrapper--hidden");
  categoriesTable.classList.remove("unavailable__table-wrapper--hidden");
  overlay.classList.remove("overlay--active");

  if (noResultsMessage) {
    noResultsMessage.remove();
  }
}
