export default function resetSelectedProducts() {
  const selectedCountElement = document.querySelector(
    ".unavailable__selected-count--products"
  );
  if (selectedCountElement) selectedCountElement.textContent = "0";

  const productsTable = document.querySelector(".unavailable__table--products");
  if (!productsTable) return;

  const checkboxes = productsTable.querySelectorAll('input[type="checkbox"]');
  checkboxes.forEach((checkbox) => {
    checkbox.checked = false;
    checkbox.disabled = false;
  });

  const rows = productsTable.querySelectorAll("tbody tr");
  rows.forEach((row) => {
    row.classList.remove("selected", "disabled");
  });

  const oldHandler = productsTable.getAttribute("data-handler");
  if (oldHandler && window[oldHandler]) {
    const selectedProducts = new Set();
    const event = new Event("reset");
    window[oldHandler](event, selectedProducts);
  }
}
